// InfoServer   
class NetMessageQueue : public MsgQueue<pNetMessage> {
public:
	~NetMessageQueue() {
		Clear();
	}

	void Clear() {
		std::deque<pNetMessage>::iterator it;

		m_lock.lock();
		for (it = m_queue.begin(); it != m_queue.end(); it++) {
			FreeNetMessage(*it);
		}
		m_queue.clear();
		m_lock.unlock();
	}
};

